#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, C, K;
        scanf("%d %d %d", &N, &C, &K);
        int* S = (int*)malloc(N * sizeof(int));
        int* M = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &S[i], &M[i]);
        }
        long long* dp = (long long*)malloc((K + 1) * sizeof(long long));
        dp[0] = 1;
        for (int i = 0; i < N; i++) {
            long long* new_dp = (long long*)malloc((K + 1) * sizeof(long long));
            for (int j = 0; j <= K; j++) {
                new_dp[j] = 0;
            }
            for (int j = 0; j <= K; j++) {
                for (int k = 0; k <= j; k++) {
                    new_dp[j] = (new_dp[j] + dp[k] * (C - (i > 0 && S[i] == S[i - 1] ? 1 : 0))) % MOD;
                }
            }
            free(dp);
            dp = new_dp;
        }
        long long ans = 0;
        for (int i = 0; i <= K; i++) {
            ans = (ans + dp[i]) % MOD;
        }
        printf("%lld\n", ans);
        free(dp);
        free(S);
        free(M);
    }
    return 0;
}

